import java.util.*;

public class ArrayListExample {
    public static void main(String[] args) {
        // Creating ArrayLists
        System.out.println("=== Creating ===");
        ArrayList<String> names = new ArrayList<>();
        ArrayList<Integer> numbers = new ArrayList<>(Arrays.asList(10, 20, 30));

        // Adding elements
        System.out.println("=== Adding ===");
        names.add("Alice");
        names.add("Bob");
        names.add("Charlie");
        names.add(1, "Diana");  // Insert at index 1
        System.out.println("After adding: " + names);

        // Accessing elements
        System.out.println("=== Accessing ===");
        System.out.println("First name: " + names.get(0));
        System.out.println("Size: " + names.size());

        // Iterating
        System.out.println("=== For-each loop ===");
        for (String name : names) {
            System.out.println("  " + name);
        }

        System.out.println("=== For loop with index ===");
        for (int i = 0; i < names.size(); i++) {
            System.out.println("  Index " + i + ": " + names.get(i));
        }

        // Removing elements
        System.out.println("=== Removing ===");
        names.remove(2);  // Remove by index
        names.remove("Alice");  // Remove by object
        System.out.println("After removing: " + names);

        // Checking contents
        System.out.println("=== Checking ===");
        System.out.println("Contains 'Bob'? " + names.contains("Bob"));
        System.out.println("Index of 'Bob': " + names.indexOf("Bob"));
        System.out.println("Is empty? " + names.isEmpty());

        // ArrayList with different types
        System.out.println("=== Numbers ===");
        numbers.add(40);
        numbers.add(50);
        System.out.println("Numbers: " + numbers);

        // Null handling
        System.out.println("=== Null values ===");
        ArrayList<String> nullable = new ArrayList<>();
        nullable.add(null);
        nullable.add("Hello");
        nullable.add(null);
        System.out.println("With nulls: " + nullable);
        System.out.println("Size: " + nullable.size());

        // ArrayList to array
        System.out.println("=== To Array ===");
        String[] array = names.toArray(new String[0]);
        System.out.println("Array: " + Arrays.toString(array));

        // Clear
        System.out.println("=== Clear ===");
        names.clear();
        System.out.println("After clear: " + names);
        System.out.println("Size: " + names.size());
        System.out.println("Is empty? " + names.isEmpty());
    }
}

phase2.brokenCode:
import java.util.*;

public class Test {
    public static void main(String[] args) {
        ArrayList<String> list = new ArrayList<>();
        list.add("A");
        list.add("B");

        // Removing while iterating
        for (String s : list) {
            if (s.equals("A")) {
                list.remove(s);  // ERROR!
            }
        }
        System.out.println(list);
    }
}

phase2.explanation:
ConcurrentModificationException! You can't modify a list while iterating over it with a for-each loop.

The for-each loop uses an internal iterator that checks for modifications.

FIX: Use Iterator and its remove() method:
Iterator<String> it = list.iterator();
while (it.hasNext()) {
    String s = it.next();
    if (s.equals("A")) {
        it.remove();  // Safe!
    }
}

Or use removeIf(): list.removeIf(s -> s.equals("A"));

phase3.solution:
import java.util.*;

public class ArrayListPractice {
    public static void main(String[] args) {
        ArrayList<String> fruits = new ArrayList<>(
            Arrays.asList("Apple", "Banana", "Orange", "Apple", "Grape", "Banana")
        );

        System.out.println("Fruits: " + fruits);

        fruits.removeIf(s -> s.equals("Banana"));
        System.out.println("After removing bananas: " + fruits);

        System.out.println("Size: " + fruits.size());
        System.out.println("Contains 'Orange'? " + fruits.contains("Orange"));
        System.out.println("Element at index 2: " + fruits.get(2));
    }
}
